        },
        "value": {
          "path": "/intake/newJobCode"
        },
        "displayStyle": "chips",
        "variant": "mutuallyExclusive",
        "checks": [
          {
            "condition": {
              "call": "required",
              "args": {
                "value": {
                  "path": "/intake/newJobCode"
                }
              }
            },
            "message": "A new job title is required for a promotion."
          }
        ]
      },
      {
        "id": "pay_rate_field",
        "component": "TextField",
        "label": "2. Proposed New Hourly Pay Rate ($)",
        "variant": "number",
        "value": {
          "path": "/intake/newPayRate"
        },
        "checks": [
          {
            "condition": {
              "call": "required",
              "args": {
                "value": {
                  "path": "/intake/newPayRate"
                }
              }
            },
            "message": "The proposed pay rate is required."
          },
          {
            "condition": {
              "call": "numeric",
              "args": {
                "value": {
                  "path": "/intake/newPayRate"
                },
                "min": 1
              }
            },
            "message": "The pay rate must be a positive number."
          }
        ]
      },
      {
        "id": "date_field",
        "component": "DateTimeInput",
        "label": "3. Effective Date of Change",
        "enableDate": true,
        "value": {
          "path": "/intake/effectiveDate"
        },
        "checks": [
          {
            "condition": {
              "call": "required",
              "args": {
                "value": {
                  "path": "/intake/effectiveDate"
                }
              }
            },
            "message": "An effective date is required."
          }
        ]
      },
      {
        "id": "next_button",
        "component": "Button",
        "child": "next_button_text",
        "action": {
          "event": {
            "name": "check_promotion_details",
            "context": {
              "employeeId": "EMP1001",
              "currentPayRate": {
                "path": "/intake/currentPayRate"
              },
              "newJobCode": {
                "path": "/intake/newJobCode"
              },
              "newPayRate": {
                "path": "/intake/newPayRate"
              },
              "effectiveDate": {
                "path": "/intake/effectiveDate"
              }
            }
          }
        },
        "variant": "primary"
      },
      {
        "id": "next_button_text",
        "component": "Text",
        "text": "Review & Check Policy Compliance"
      }
    ]
  }
}
